def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        if bins[i] == 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / bins[i]
        if usage_ratio > 1:
            priorities[i] = 1000 * usage_ratio
        elif usage_ratio == 1:
            priorities[i] = 10
        else:
            log_val = np.log(1 - usage_ratio + 1e-9)
            if log_val < -1:
                priorities[i] = -log_val * 5
            else:
                priorities[i] = -log_val
        if bins[i] < 0.1:
            priorities[i] += 50
        elif bins[i] < 1:
            priorities[i] += 10
    if np.any(bins == 0):
        priorities[bins == 0] = np.inf
    return priorities
